@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}
else
{
    <BoardSummaryBar Tasks="allTasks" />
    <BoardSearchBar @bind-SearchTerm="searchTerm" />

    <div class="row g-3">
        <BoardColumn Status="To Do"
                     Tasks="GetFilteredTasks("To Do")"
                     RightStatus="In Progress"
                     OnMoveTask="HandleMoveTask"
                     OnAddTask="args => HandleAddTask("To Do", args)" />

        <BoardColumn Status="In Progress"
                     Tasks="GetFilteredTasks("In Progress")"
                     LeftStatus="To Do"
                     RightStatus="Done"
                     OnMoveTask="HandleMoveTask"
                     OnAddTask="args => HandleAddTask("In Progress", args)" />

        <BoardColumn Status="Done"
                     Tasks="GetFilteredTasks("Done")"
                     LeftStatus="In Progress"
                     OnMoveTask="HandleMoveTask"
                     OnAddTask="args => HandleAddTask("Done", args)" />
    </div>
}

@code {
    private List<TaskItem> allTasks = [];
    private string searchTerm = "";
    private bool loading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        try
        {
            loading = true;
            errorMessage = null;
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            loading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));
        }
        return tasks.ToList();
    }

    private async Task HandleMoveTask((int TaskId, string NewStatus) move)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(move.TaskId, move.NewStatus);
            var task = allTasks.First(t => t.Id == move.TaskId);
            allTasks[allTasks.IndexOf(task)] = task with { Status = move.NewStatus };
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task HandleAddTask(string status, (string Title, string Assignee, string Priority, DateTime DueDate) data)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
            allTasks.Add(newTask);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to add task: {ex.Message}";
        }
    }
}

